def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            # Return a phrase that can be used after the subject, e.g., "is American"
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                adj = "American"
            elif low_obj.startswith("the "):
                adj = obj[4:].strip()
            else:
                # Try to form an adjective by adding 'ian' if not already an adjective
                adj = obj
            return f"is {adj}"
        if p == "occupation":
            # Use a more natural verb for astronauts' roles
            return f"served as a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; describe crew membership in the mission
            return f"was a crew member of {obj}"
        if p == "dateofretirement":
            # Phrase retirement date naturally
            try:
                from datetime import datetime
                dt = datetime.strptime(obj.strip('"'), "%B %Y")
                return f"retired in {dt.strftime('%B %Y')}"
            except Exception:
                # Fallback to generic wording
                return f"retired on {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "commander":
            # For mission subjects, express role as passive verb
            return f"was commanded by {obj}"
        if p == "backuppilot":
            # Phrase the backup pilot role with possessive form
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            # Use plural form and a natural connector
            return f"had crew member {obj}"
        if p == "leader":
            # Express leadership as a property of the entity without repeating the subject
            return f"is led by {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    # First, handle special case: combine astronaut‑mission crew information into one sentence
    mission_crew = {}   # mission -> set of crew member names
    # Gather astronauts that have a 'mission' predicate
    for t in triples:
        if t.predicate.lower().replace(" ", "") == "mission":
            mission = t.object.strip().strip('"')
            mission_crew.setdefault(mission, set()).add(t.subject.strip())
    # Gather explicit crewMembers triples
    for t in triples:
        if t.predicate.lower().replace(" ", "") == "crewmembers":
            mission = t.subject.strip()
            member = t.object.strip().strip('"')
            mission_crew.setdefault(mission, set()).add(member)

    sentences = []
    processed_missions = set()
    # Create combined crew sentences
    for mission, members in mission_crew.items():
        if not members:
            continue
        member_list = list(members)
        if len(member_list) == 1:
            crew_phrase = f"{member_list[0]} was a crew member of {mission}"
        else:
            # join with commas and 'and'
            crew_phrase = ", ".join(member_list[:-1]) + f", and {member_list[-1]} were crew members of {mission}"
        sentences.append(crew_phrase + ".")
        processed_missions.add(mission)

    # Now handle the remaining triples that were not part of the combined crew sentences
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        # Skip triples already used in crew combination
        if t.predicate.lower().replace(" ", "") in ("mission", "crewmembers"):
            # If this triple contributed to a processed mission, skip it
            if t.predicate.lower().replace(" ", "") == "mission" and t.object.strip().strip('"') in processed_missions:
                continue
            if t.predicate.lower().replace(" ", "") == "crewmembers" and t.subject.strip() in processed_missions:
                continue
        groups[t.subject].append(t)

    for subj, items in groups.items():
        subject_phrase = subj
        multi_pred_objs = {}
        descriptors = []
        for t in items:
            pred_norm = t.predicate.lower().replace(" ", "")
            if pred_norm == "crewmembers":
                multi_pred_objs.setdefault(pred_norm, []).append(t.object.strip().strip('"'))
                continue
            d = phrase(subj, t.predicate, t.object)
            if d.startswith(f"{subj}'s "):
                sentences.append(f"{d}.")
            else:
                descriptors.append(d)
        if "crewmembers" in multi_pred_objs:
            members = multi_pred_objs["crewmembers"]
            if len(members) == 1:
                crew_clause = f"had crew member {members[0]}"
            else:
                crew_clause = "had crew members " + ", ".join(members[:-1]) + f", and {members[-1]}"
            descriptors.append(crew_clause)

        if not descriptors:
            continue
        if len(descriptors) == 1:
            sent = f"{subject_phrase} {descriptors[0]}."
        else:
            body = ", ".join(descriptors[:-1])
            sent = f"{subject_phrase} {body}, and {descriptors[-1]}."
        sentences.append(sent)

    return " ".join(sentences)

